{
  "executive_summary": "A two-tier ML architecture separating the real-time serving path (optimized for 100ms P99) from the offline training pipeline (weekly batch). The serving layer uses a pre-loaded model behind a lightweight inference service with blue-green model deployment for instant rollback. The training pipeline is a scheduled batch job that validates new models against the current champion before promotion. Designed for a 4-person team — simplicity is the dominant constraint.",

  "architecture": {
    "components": [
      {
        "name": "Feature Store",
        "responsibility": "Pre-computes and serves features for both training and inference. Stores static features (zone metadata, distance matrices) and real-time features (current courier load, weather). Ensures training-serving skew is eliminated by sharing the same feature definitions.",
        "boundaries": "Owns feature definitions and materialization. Does NOT own raw order data or model artifacts."
      },
      {
        "name": "Inference Service",
        "responsibility": "Loads the current model into memory, accepts prediction requests over gRPC/HTTP, computes features from the Feature Store, and returns predicted delivery time. Stateless — the model is a read-only artifact loaded at startup or swapped via signal.",
        "boundaries": "Owns only the serving path. Does NOT train models, validate models, or decide which model to promote."
      },
      {
        "name": "Training Pipeline",
        "responsibility": "Weekly scheduled job that pulls historical delivery data, joins with features from the Feature Store, trains a new candidate model, and writes the versioned artifact to the Model Registry.",
        "boundaries": "Owns the training DAG only. Does NOT serve predictions or decide promotion — it produces candidates."
      },
      {
        "name": "Model Registry",
        "responsibility": "Versioned storage of model artifacts with metadata (training date, dataset hash, validation metrics). Tracks which version is 'champion' (live) and 'challenger' (candidate). Supports instant rollback by re-pointing the champion label.",
        "boundaries": "Owns model versioning and promotion state. Simple implementation: S3 bucket + a metadata table (DynamoDB/Postgres row)."
      },
      {
        "name": "Validation & Promotion Gate",
        "responsibility": "After training produces a candidate, runs it against a holdout set and compares metrics (MAE, P95 error) to the current champion. If the candidate wins, promotes it. If not, alerts the team and keeps the current champion.",
        "boundaries": "Owns the go/no-go decision for model promotion. Does NOT own the model artifacts themselves."
      },
      {
        "name": "Prediction Logger",
        "responsibility": "Logs every inference request (features + prediction) and later joins with actual delivery times to create labeled training data for the next cycle. This closes the feedback loop.",
        "boundaries": "Owns the prediction log and label-join pipeline. Writes to the training data store, does NOT read from it during serving."
      },
      {
        "name": "Monitoring & Alerting",
        "responsibility": "Tracks serving latency (P50/P95/P99), prediction distribution drift, and model accuracy on recent deliveries. Triggers alerts if P99 > 80ms (headroom) or if prediction error degrades beyond threshold.",
        "boundaries": "Read-only observer. Can trigger rollback alerts but does NOT autonomously roll back — that's a human decision via the Model Registry."
      }
    ],
    "interfaces": [
      {
        "from": "Checkout Service (external)",
        "to": "Inference Service",
        "contract": "POST /predict {weight, distance, zone, time_of_day, weather, courier_load} → {estimated_minutes, confidence_interval, model_version}",
        "coupling_type": "synchronous — on the critical checkout path"
      },
      {
        "from": "Inference Service",
        "to": "Feature Store",
        "contract": "In-process lookup or local cache of pre-computed feature vectors. No network hop for static features; sub-ms Redis/local-cache lookup for real-time features (courier load, weather).",
        "coupling_type": "runtime dependency — must be fast, use local cache with async refresh"
      },
      {
        "from": "Inference Service",
        "to": "Model Registry",
        "contract": "On startup or SIGHUP: pull model artifact by 'champion' label. Model loaded into memory — no per-request calls to registry.",
        "coupling_type": "deployment-time only — no runtime coupling"
      },
      {
        "from": "Inference Service",
        "to": "Prediction Logger",
        "contract": "Async fire-and-forget log of {request_id, features, prediction, model_version, timestamp}. Buffered and flushed in batches. Must NOT add latency to the serving path.",
        "coupling_type": "asynchronous — failure does not affect serving"
      },
      {
        "from": "Training Pipeline",
        "to": "Feature Store",
        "contract": "Batch read of historical feature vectors joined with delivery outcomes. Same feature definitions as serving to prevent skew.",
        "coupling_type": "batch — offline only"
      },
      {
        "from": "Training Pipeline",
        "to": "Model Registry",
        "contract": "PUT /models/{version} with artifact + metadata (metrics, dataset hash, training params).",
        "coupling_type": "write-only at end of training"
      },
      {
        "from": "Validation & Promotion Gate",
        "to": "Model Registry",
        "contract": "Read candidate and champion metrics → compare → update champion label if candidate wins.",
        "coupling_type": "synchronous but offline — not on serving path"
      }
    ],
    "data_flow": "Checkout → Inference Service (feature lookup from local cache/Redis, model inference in-process, async log to Prediction Logger) → response in <100ms. Offline: Prediction Logger joins predictions with actual delivery times → writes labeled data to training store → weekly Training Pipeline reads labeled data + Feature Store → trains candidate → writes to Model Registry → Validation Gate compares candidate vs champion → promotes or rejects → Inference Service picks up new champion on next deploy/signal.",
    "patterns_used": [
      {
        "pattern": "Champion/Challenger Model Deployment",
        "rationale": "Enables safe weekly model updates with automatic validation before promotion. Rollback is instant — just re-label the previous version as champion and restart/signal the inference service."
      },
      {
        "pattern": "Feature Store (shared offline/online)",
        "rationale": "The #1 cause of ML system failures is training-serving skew. A shared feature store with identical definitions for batch training and online serving eliminates this class of bugs entirely."
      },
      {
        "pattern": "In-Process Model Serving (no external model server)",
        "rationale": "For a 4-person team, running a separate model server (TF Serving, Triton) adds operational burden without benefit. A lightweight model (gradient-boosted trees via LightGBM/XGBoost) loaded into a Python/Rust service process achieves sub-10ms inference, well within the 100ms budget."
      },
      {
        "pattern": "Async Prediction Logging with Batch Flush",
        "rationale": "Logging must not add latency to the serving path. Buffer predictions in-process, flush to durable storage (S3/Kafka) in batches on a background thread."
      },
      {
        "pattern": "Closed Feedback Loop",
        "rationale": "Predictions are logged and later joined with actual delivery outcomes to produce training labels. This ensures the model improves on real-world performance, not just static datasets."
      }
    ]
  },

  "domain_model": {
