        "aggregates": ["ModelVersion (entity: artifact + metrics + promotion state)", "TrainingRun (entity: dataset hash, hyperparams, output model version)"]
      },
      {
        "name": "Feature Management",
        "classification": "supporting",
        "aggregates": ["FeatureDefinition (entity: name, computation logic, shared between training and serving)", "FeatureValue (value object: computed feature for a given input)"]
      },
      {
        "name": "Delivery Outcomes (external)",
        "classification": "generic",
        "aggregates": ["DeliveryRecord (entity: order_id, actual_delivery_time, used for label generation — owned by the logistics platform, not by us)"]
      }
    ],
    "context_map": [
      {
        "upstream": "Delivery Outcomes (logistics platform)",
        "downstream": "Model Lifecycle (Training Pipeline)",
        "relationship": "Conformist — we consume their delivery records as-is; we do not dictate their schema"
      },
      {
        "upstream": "Model Lifecycle",
        "downstream": "Real-Time Serving",
        "relationship": "Customer-Supplier — Model Lifecycle produces artifacts that Serving consumes. Serving defines what artifact format it needs (ONNX/pickle), and Training must produce it."
      },
      {
        "upstream": "Feature Management",
        "downstream": "Real-Time Serving",
        "relationship": "Shared Kernel — feature definitions are shared code between training and serving to prevent skew"
      },
      {
        "upstream": "Feature Management",
        "downstream": "Model Lifecycle",
        "relationship": "Shared Kernel — same feature definitions used in batch training"
      }
    ]
  },

  "trade_offs": [
    {
      "decision": "In-process model (LightGBM/XGBoost) over deep learning model server",
      "gains": "Sub-10ms inference latency, trivial deployment (single binary/container), no GPU costs, easy for 4-person team to operate",
      "sacrifices": "Cannot serve deep learning models without architecture change. Feature engineering becomes more important than with neural nets.",
      "alternatives_considered": ["TensorFlow Serving / Triton for neural net — rejected: operational overhead too high for 4-person team, latency budget doesn't demand it", "ONNX Runtime — viable future upgrade path if model complexity grows"]
    },
    {
      "decision": "Weekly batch retraining over online/incremental learning",
      "gains": "Simple, debuggable, reproducible training runs. Easy to validate before promotion. Matches team capacity.",
      "sacrifices": "Model cannot adapt to intra-week changes (e.g., sudden weather events). Up to 7 days of label lag.",
      "alternatives_considered": ["Online learning — rejected: harder to debug, harder to validate, higher operational risk for small team", "Daily retraining — viable if weekly proves insufficient, same architecture scales down to daily cadence"]
    },
    {
      "decision": "Champion/Challenger with manual rollback trigger over automated canary rollback",
      "gains": "Simpler to implement and reason about. Rollback is a single command. No complex traffic-splitting infrastructure needed.",
      "sacrifices": "No automatic rollback — requires human to notice degradation and act. Mitigated by monitoring alerts.",
      "alternatives_considered": ["Shadow mode / canary with automatic rollback — rejected for V1: adds complexity; revisit when traffic volume justifies it"]
    },
    {
      "decision": "Shared Feature Store (single source of truth) over separate feature pipelines",
      "gains": "Eliminates training-serving skew — the most common and insidious bug in ML systems",
      "sacrifices": "Adds a component to build and maintain. For V1, can be as simple as a shared Python module with feature transforms + Redis for real-time features.",
      "alternatives_considered": ["Separate feature logic in training and serving — rejected: skew bugs are inevitable and extremely hard to diagnose"]
    }
  ],

  "flexibility_points": [
    {
      "area": "Model algorithm",
      "evolution_path": "The serving layer loads a serialized model artifact — it doesn't care if it's XGBoost, LightGBM, or an ONNX-exported neural net. Swapping algorithms requires only changing the training pipeline and ensuring the output format is compatible."
    },
    {
      "area": "Retraining cadence",
      "evolution_path": "The training pipeline is a scheduled job. Changing from weekly to daily or hourly is a config change, not an architecture change. The pipeline is idempotent."
    },
    {
      "area": "Feature additions",
      "evolution_path": "New features (e.g., traffic data, courier ratings) are added to the Feature Store definitions. Both training and serving pick them up. Model is retrained with new features. No serving code changes needed beyond feature vector size."
    },
    {
      "area": "Scaling inference horizontally",
      "evolution_path": "Inference service is stateless (model loaded at startup, no shared state between requests). Horizontal scaling is adding more replicas behind a load balancer."
    }
  ],

  "rigidity_points": [
    {
      "area": "Feature Store as shared kernel",
      "reason": "Feature definitions MUST be shared between training and serving. This is intentional rigidity — allowing them to diverge would introduce training-serving skew, which is the #1 operational risk in ML systems."
